    private static double testBatch(int total, int batchSize) {
        int size = 0;
        for (int i = 0; i < total / batchSize; i++) {
            HashMap<Integer, List<Integer>> x1 = new HashMap<>();
            for (int j = 0; j < batchSize; j++) {
                int random = RandomUtils.nextInt(0, 10000000);
                x1.putIfAbsent(random % 50, new ArrayList<>());
                x1.get(random % 50).add(random);
            }
            size += x1.size();
        }
        return size;
    }
